(function() {
  try {
    // 複数のパターンでモーダルを閉じるボタンを探す
    const closeButtons = [
      ...Array.from(document.querySelectorAll('button[role="button"]')).filter(b => 
        (b.textContent || '').includes('Got it') || 
        (b.textContent || '').includes('了解') ||
        (b.getAttribute('aria-label') || '').includes('Got it') ||
        (b.getAttribute('aria-label') || '').includes('了解')
      ),
      document.querySelector('[data-testid="app-bar-close"]'),
      document.querySelector('button[aria-label*="Close"]'),
      document.querySelector('button[aria-label*="閉じる"]')
    ].filter(Boolean);

    if (closeButtons.length > 0) {
      closeButtons[0].click();
      return { didAction: true, reason: 'Clicked modal close button' };
    }

    // モーダルが見つからない場合は成功扱い（既に閉じている可能性）
    return { didAction: true, reason: 'Modal close button not found (may already be closed)' };
  } catch(e) {
    return { didAction: false, reason: String(e) };
  }
})()

(function() {
  try {
    // アカウント凍結検出: ログインページが表示されているか文言をチェック（フォロワー数取得・保存と同じロジック）
    const loginButton = document.querySelector('[data-testid="login"]');
    const suspendedText1 = document.body.textContent?.includes('いま起きていることを見つけよう');
    const suspendedText2 = document.body.textContent?.includes('Xなら、「いま」起きていることをいち早くチェックできます。');

    if (loginButton || (suspendedText1 && suspendedText2)) {
      return {
        ok: false,
        error: 'アカウントが凍結されている可能性があります（ログインページが表示されています）',
        didAction: false,
        suspended: true
      };
    }
    return { ok: true, didAction: true, reason: 'Ban check passed' };
  } catch (e) {
    return { ok: false, error: 'エラー: ' + (e.message || String(e)), didAction: false };
  }
})()

(function() {
  try {
    const loginButton = document.querySelector('[data-testid="login"]');
    const suspendedText1 = document.body.textContent?.includes('いま起きていることを見つけよう');
    const suspendedText2 = document.body.textContent?.includes('Xなら、「いま」起きていることをいち早くチェックできます。');
    if (loginButton || (suspendedText1 && suspendedText2)) {
      return { ok: false, error: 'アカウントが凍結されている可能性があります', didAction: false, suspended: true };
    }
    let followerLink = document.querySelector('a[href*="/verified_followers"]') || document.querySelector('a[href*="/followers"]');
    let followingLink = document.querySelector('a[href*="/following"]');
    const profileHeader = document.querySelector('[data-testid="UserProfileHeader_Items"]') || document.querySelector('[data-testid="UserName"]')?.closest('div')?.parentElement;
    if (profileHeader) {
      if (!followerLink) followerLink = profileHeader.querySelector('a[href*="/followers"], a[href*="/verified_followers"]');
      if (!followingLink) followingLink = profileHeader.querySelector('a[href*="/following"]');
    }
    let followerCount = null, followingCount = null;
    if (followerLink) { const m = (followerLink.textContent||'').match(/([\d,]+)/); if (m) followerCount = parseInt(m[1].replace(/,/g,''),10); }
    if (followingLink) { const m = (followingLink.textContent||'').match(/([\d,]+)/); if (m) followingCount = parseInt(m[1].replace(/,/g,''),10); }
    if (profileHeader && (followerCount===null || followingCount===null)) {
      const ht = profileHeader.textContent || '';
      if (followerCount===null) { const fm = ht.match(/([\d,]+)\s*(フォロワー|Followers|follower)/i); if (fm) followerCount = parseInt(fm[1].replace(/,/g,''),10); }
      if (followingCount===null) { const fm = ht.match(/([\d,]+)\s*(フォロー|Following)/i); if (fm) followingCount = parseInt(fm[1].replace(/,/g,''),10); }
    }
    if (followerCount!==null || followingCount!==null) return { ok: true, followerCount, followingCount, didAction: true, reason: 'フォロワー数: '+(followerCount!==null?followerCount:'取得失敗')+', フォロー数: '+(followingCount!==null?followingCount:'取得失敗') };
    return { ok: false, error: 'フォロワー数またはフォロー数が見つかりませんでした', didAction: false };
  } catch (e) { return { ok: false, error: 'エラー: '+(e.message||String(e)), didAction: false }; }
})()

(function() { 
  try { 
    // 複数の方法でボタンを探す
    let btn = null;

    // 方法1: data-testid
    btn = document.querySelector('[data-testid="tweetButton"]') ||
          document.querySelector('[data-testid="tweetButtonInline"]');

    // 方法2: テキストコンテンツで "Post" を含むボタンを探す
    if (!btn) {
      btn = Array.from(document.querySelectorAll('button')).find(b => {
        const text = (b.textContent || '').trim();
        return text === 'Post' && !b.disabled;
      });
    }

    // 方法3: aria-label
    if (!btn) {
      btn = document.querySelector('button[aria-label*="Post"]') || 
            document.querySelector('button[aria-label*="投稿"]');
    }

    if (btn && !btn.disabled) { 
      btn.click(); 
      return { didAction: true, reason: 'post button clicked' }; 
    } 

    return { didAction: false, reason: btn ? 'post button disabled' : 'post button not found' }; 
  } catch(e) { 
    return { didAction: false, reason: String(e) }; 
  } 
})()
